nta.declaration:
// ================= MOVE → QUADRANT REQUIREMENTS =================
// M1: Q2 + Q3
// M2: Q4 + Q1
// M3: Q4 + Q3
// M4: Q2 + Q1

// M5: Q2 + Q1
// M6: Q4 + Q3
// M7: Q4 + Q3
// M8: Q2 + Q1

// M9:  Q2 + Q3
// M10: Q2 + Q3
// M11: Q4 + Q1
// M12: Q4 + Q1

// ================= MOVEMENT → QUADRANT MAP =================
// Each move defines required exclusive spatial resources

const int M1 = 1;   // N→S
const int M2 = 2;   // S→N
const int M3 = 3;   // E→W
const int M4 = 4;   // W→E

const int M5 = 5;   // N→E
const int M6 = 6;   // E→S
const int M7 = 7;   // S→W
const int M8 = 8;   // W→N

const int M9  = 9;  // N→W
const int M10 = 10; // W→S
const int M11 = 11; // S→E
const int M12 = 12; // E→N

// ================= SCHEDULER STATE =================
// rotates through M1–M12 safely
//int moveIndex = 1;
// ================= TIME =================
clock t_tr1, t_tr2, t_tr3, t_tr4, t_tr5, t_tr6, t_tr7, t_tr8;
clock wait_clk, exec_clk, comm_clk, sched_clk, switch_clk;

// ================= CONSTANTS =================
const int MAX_WAIT = 4;
const int SLOT_TIME = 5;
const int SCHED_DEADLINE = 2;
const int SENSOR_PERIOD = 1;

// ================= Z2 QUADRANTS =================
bool Q1 = false;
bool Q2 = false;
bool Q3 = false;
bool Q4 = false;

// ================= STATE =================
int[0,MAX_WAIT] queue_len = 0;         // vehicles waiting for service (not executing) -queue_len can never be less than 0+q ueue_len can never be greater than MAX_WAIT
int emergency_flag = 0;
bool system_busy = false;
bool has_proposal;
int selectedVehicle = -1;
int generatedMove = 1;
int requestedVehicle = -1;
int vehicleRequest[4];
bool requestPending[4];
// ================= CHANNELS =================
broadcast chan vehicle_arrive;
broadcast chan request_next;

broadcast chan schedule_propose;
broadcast chan schedule_exc;
broadcast chan schedule_reject;

broadcast chan reserve_slot;
broadcast chan execute;

urgent broadcast chan emergency_detect;
broadcast chan priority_override;

bool emergency_active = false;
const int MAX_VEHICLES = 4;

int vehicleMove[MAX_VEHICLES];
bool vehicleActive[MAX_VEHICLES];
int generatedVehicle = 0;

// Round-robin selection:
// 1) pick first available vehicle starting from rrIndex
// 2) then rotate rrIndex so next cycle starts from next vehicle
// ensures fairness and prevents starvation
int rrIndex = 0;

int waitTime[4];

// ================= WAIT TIME AGING =================
// Each scheduling cycle increases waiting time for all vehicles.
// This models starvation prevention by prioritizing older requests.
//
// ================= SCHEDULER DECISION =================
// selectedVehicle = Round-Robin scan starting from rrIndex
// rrIndex is then rotated to ensure fairness across cycles
//
// Combined effect:
// - RR ensures fairness in selection order
// - waitTime tracks how long each request has been waiting

// Conflict cost of each vehicle request.
// Higher cost = movement is less preferred by scheduler.
// Simple conflict heuristic:
// Straight movements -> cost 1
// Turning movements -> cost 2
int cost[4];
int score[4];
int i;

transition.label:
// ================= AGING UPDATE ================= waitTime[0] = waitTime[0] + 1, waitTime[1] = waitTime[1] + 1, waitTime[2] = waitTime[2] + 1, waitTime[3] = waitTime[3] + 1,
// ================= SCORE COMPUTATION ================= score[0] = waitTime[0] - cost[0], score[1] = waitTime[1] - cost[1], score[2] = waitTime[2] - cost[2], score[3] = waitTime[3] - cost[3],
//movement conflict cost awareness selectedVehicle = (requestPending[0] && vehicleActive[0] && (score[0] >= score[1] || !requestPending[1]) && (score[0] >= score[2] || !requestPending[2]) && (score[0] >= score[3] || !requestPending[3])) ? 0 : (requestPending[1] && vehicleActive[1] && (score[1] >= score[0] || !requestPending[0]) && (score[1] >= score[2] || !requestPending[2]) && (score[1] >= score[3] || !requestPending[3])) ? 1 : (requestPending[2] && vehicleActive[2] && (score[2] >= score[0] || !requestPending[0]) && (score[2] >= score[1] || !requestPending[1]) && (score[2] >= score[3] || !requestPending[3])) ? 2 : (requestPending[3] && vehicleActive[3]) ? 3 : -1

nta.system:
V0 = Vehicle(0);
V1 = Vehicle(1);
V2 = Vehicle(2);
V3 = Vehicle(3);
system VehicleGenerator, Scheduler, IntersectionController, EmergencyHandler, V0, V1, V2, V3;
